  return (
    <dl className={cn("divide-y",className)} {...props}>
      {fields.map((field) => {
        if (field.condition&&!field.condition(data)) return null;

        const Component=field.component;
        const value=String(data[field.id]);

        return (
          <div key={field.id.toString()}>
            {field.type==="readonly"? (
