"use client";

import {Kbd} from "@/components/custom/kbd";
import {useDataTable} from "@/components/data-table/data-table-provider";
import {Button} from "@/components/ui/button";
import {Separator} from "@/components/ui/separator";
import {
  Sheet,
  SheetClose,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet";
import {Skeleton} from "@/components/ui/skeleton";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import {cn} from "@/lib/utils";
import {ChevronDown,ChevronUp,X} from "lucide-react";
import * as React from "react";

export interface DataTableSheetDetailsProps {
  title?: React.ReactNode;
  titleClassName?: string;
  children?: React.ReactNode;
}

export function DataTableSheetDetails({
  title,
  titleClassName,
  children,
}: DataTableSheetDetailsProps) {
  const {table,rowSelection,isLoading}=useDataTable();

  const selectedRowKey=Object.keys(rowSelection)?.[0];

  const selectedRow=React.useMemo(() => {
    if (isLoading&&!selectedRowKey) return;
    return table
      .getCoreRowModel()
      .flatRows.find((row) => row.id===selectedRowKey);
  },[selectedRowKey,isLoading,table]);

  const index=table
    .getCoreRowModel()
    .flatRows.findIndex((row) => row.id===selectedRow?.id);

  const nextId=React.useMemo(
    () => table.getCoreRowModel().flatRows[index+1]?.id,
    [index,isLoading,table],
  );

  const prevId=React.useMemo(
    () => table.getCoreRowModel().flatRows[index-1]?.id,
    [index,isLoading,table],
  );

  const onPrev=React.useCallback(() => {
    if (prevId) table.setRowSelection({[prevId]: true});
  },[prevId,isLoading,table]);

  const onNext=React.useCallback(() => {
    if (nextId) table.setRowSelection({[nextId]: true});
  },[nextId,isLoading,table]);

  React.useEffect(() => {
    const down=(e: KeyboardEvent) => {
      if (!selectedRowKey) return;

      // REMINDER: prevent dropdown navigation inside of sheet to change row selection
      const activeElement=document.activeElement;
      const isMenuActive=activeElement?.closest('[role="menu"]');

      if (isMenuActive) return;

      if (e.key==="ArrowUp") {
        e.preventDefault();
        onPrev();
      }
      if (e.key==="ArrowDown") {
        e.preventDefault();
        onNext();
      }
    };

    document.addEventListener("keydown",down);
    return () => document.removeEventListener("keydown",down);
  },[selectedRowKey,onNext,onPrev]);

  return (
    <Sheet
      open={!!selectedRowKey}
      onOpenChange={() => {
        // REMINDER: focus back to the row that was selected
        // We need to manually focus back due to missing Trigger component
        const el=selectedRowKey
          ? document.getElementById(selectedRowKey)
          :null;
        table.resetRowSelection();

        // REMINDER: when navigating between tabs in the sheet and exit the sheet, the tab gets lost
        // We need a minimal delay to allow the sheet to close before focusing back to the row
        setTimeout(() => el?.focus(),0);
      }}
    >
      <SheetContent
        // onCloseAutoFocus={(e) => e.preventDefault()}
        className="overflow-y-auto p-0 sm:max-w-md"
      >
        <SheetHeader className="sticky top-0 z-10 border-b bg-background p-4">
          <div className="flex items-center justify-between gap-2">
            <SheetTitle className={cn(titleClassName,"truncate text-left")}>
              {isLoading&&!selectedRowKey? (
                <Skeleton className="h-7 w-36" />
              ):(
                title
              )}
            </SheetTitle>
            <div className="flex h-7 items-center gap-1">
              <TooltipProvider>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Button
                      size="icon"
                      variant="ghost"
                      className="h-7 w-7"
                      disabled={!prevId}
                      onClick={onPrev}
                    >
                      <ChevronUp className="h-5 w-5" />
                      <span className="sr-only">Previous</span>
                    </Button>
                  </TooltipTrigger>
                  <TooltipContent>
                    <p>
                      Navigate <Kbd variant="outline">↑</Kbd>
                    </p>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
              <TooltipProvider>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Button
                      size="icon"
                      variant="ghost"
                      className="h-7 w-7"
                      disabled={!nextId}
                      onClick={onNext}
                    >
                      <ChevronDown className="h-5 w-5" />
                      <span className="sr-only">Next</span>
                    </Button>
                  </TooltipTrigger>
                  <TooltipContent>
                    <p>
                      Navigate <Kbd variant="outline">↓</Kbd>
                    </p>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
              <Separator orientation="vertical" className="mx-1" />
              <SheetClose autoFocus={true} asChild>
                <Button size="icon" variant="ghost" className="h-7 w-7">
                  <X className="h-5 w-5" />
                  <span className="sr-only">Close</span>
                </Button>
              </SheetClose>
            </div>
          </div>
        </SheetHeader>
        <SheetDescription className="sr-only">
          Selected row details
        </SheetDescription>
        <div className="p-4">{children}</div>
      </SheetContent>
    </Sheet>
  );
}

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {useCopyToClipboard} from "@/hooks/use-copy-to-clipboard";
import {cn} from "@/lib/utils";
import type {Table} from "@tanstack/react-table";
import {endOfDay,endOfHour,startOfDay,startOfHour} from "date-fns";
import {
  CalendarClock,
  CalendarDays,
  CalendarSearch,
  ChevronLeft,
  ChevronRight,
  Copy,
  Equal,
  Search,
} from "lucide-react";
import type {DataTableFilterField} from "../types";

interface DataTableSheetRowActionProps<
  TData,
  TFields extends DataTableFilterField<TData>,
> extends React.ComponentPropsWithRef<typeof DropdownMenuTrigger> {
  fieldValue: TFields["value"];
  filterFields: TFields[];
  value: string|number;
  table: Table<TData>;
}

export function DataTableSheetRowAction<
  TData,
  TFields extends DataTableFilterField<TData>,
>({
  fieldValue,
  filterFields,
  value,
  children,
  className,
  table,
  onKeyDown,
  ...props
}: DataTableSheetRowActionProps<TData,TFields>) {
  const {copy,isCopied}=useCopyToClipboard();
  const field=filterFields.find((field) => field.value===fieldValue);
  const column=table.getColumn(fieldValue.toString());

  if (!field||!column) return null;

  function renderOptions() {
    if (!field) return null;
    switch (field.type) {
      case "checkbox":
        return (
          <DropdownMenuItem
            onClick={() => {
              // FIXME:
              const filterValue=column?.getFilterValue() as
                |undefined
                |Array<unknown>;
              const newValue=filterValue?.includes(value)
                ? filterValue
                :[...(filterValue||[]),value];

              column?.setFilterValue(newValue);
            }}
          >
            <Search />
            Include
          </DropdownMenuItem>
        );
      case "input":
        return (
          <DropdownMenuItem onClick={() => column?.setFilterValue(value)}>
            <Search />
            Include
          </DropdownMenuItem>
        );
      case "slider":
        return (
          <DropdownMenuGroup>
            <DropdownMenuItem
              onClick={() => column?.setFilterValue([0,value])}
            >
              {/* FIXME: change icon as it is not clear */}
              <ChevronLeft />
              Less or equal than
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column?.setFilterValue([value,5000])}
            >
              {/* FIXME: change icon as it is not clear */}
              <ChevronRight />
              Greater or equal than
            </DropdownMenuItem>
            <DropdownMenuItem onClick={() => column?.setFilterValue([value])}>
              <Equal />
              Equal to
            </DropdownMenuItem>
          </DropdownMenuGroup>
        );
      case "timerange":
        {
          const date=new Date(value);
          return (
            <DropdownMenuGroup>
              <DropdownMenuItem onClick={() => column?.setFilterValue([date])}>
                <CalendarSearch />
                Exact timestamp
              </DropdownMenuItem>
              <DropdownMenuItem
                onClick={() => {
                  const start=startOfHour(date);
                  const end=endOfHour(date);
                  column?.setFilterValue([start,end]);
                }}
              >
                <CalendarClock />
                Same hour
              </DropdownMenuItem>
              <DropdownMenuItem
                onClick={() => {
                  const start=startOfDay(date);
                  const end=endOfDay(date);
                  column?.setFilterValue([start,end]);
                }}
              >
                <CalendarDays />
                Same day
              </DropdownMenuItem>
            </DropdownMenuGroup>
          );
        }
      default:
        return null;
    }
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        className={cn(
          "rounded-md ring-offset-background focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
          "relative",
          className,
        )}
        onKeyDown={(e) => {
          if (e.key==="ArrowDown") {
            // REMINDER: default behavior is to open the dropdown menu
            // But because we use it to navigate between rows, we need to prevent it
            // and only use "Enter" to select the option
            e.preventDefault();
          }
          onKeyDown?.(e);
        }}
        {...props}
      >
        {children}
        {isCopied? (
          <div className="absolute inset-0 place-content-center bg-background/70">
            Value copied
          </div>
        ):null}
      </DropdownMenuTrigger>
      <DropdownMenuContent align="start" side="left">
        {renderOptions()}
        <DropdownMenuSeparator />
        <DropdownMenuItem
          onClick={() => copy(String(value),{timeout: 1000})}
        >
          <Copy />
          Copy value
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

