//           if (Array.isArray(val[curr])) {
//             return `${prev}${curr}:${val[curr].join(",")} `;
//           }
//           return `${prev}${curr}:${val[curr]} `;
//         }, "");
//       })
//       .safeParse(value);
// }

export function serializeColumFilters<TData>(
  columnFilters: ColumnFiltersState,
  filterFields?: DataTableFilterField<TData>[],
) {
  return columnFilters.reduce((prev, curr) => {
    const { type, commandDisabled } = filterFields?.find(
      (field) => curr.id === field.value,
    ) || { commandDisabled: true }; // if column filter is not found, disable the command by default

    if (commandDisabled) return prev;

    if (Array.isArray(curr.value)) {
      if (type === "slider") {
        return `${prev}${curr.id}:${curr.value.join(SLIDER_DELIMITER)} `;
      }
      if (type === "checkbox") {
        return `${prev}${curr.id}:${curr.value.join(ARRAY_DELIMITER)} `;
      }
      if (type === "timerange") {
        return `${prev}${curr.id}:${curr.value.join(RANGE_DELIMITER)} `;
      }
    }

    return `${prev}${curr.id}:${curr.value} `;
  }, "");
}

/**
 * BYOS (Bring Your Own Store) - Main Exports
 *
 * This module provides a pluggable state management system for data tables.
 *
 * @example
 * ```typescript
 * // 1. Define schema
 * import { createSchema, field } from '@/lib/store';
 *
 * const schema = createSchema({
 *   regions: field.array(field.string()).default([]).delimiter(','),
 *   latency: field.array(field.number()).delimiter('-'),
 *   host: field.string(),
 *   live: field.boolean().default(false),
 * });
 *
 * // 2. Create adapter (nuqs for URL state)
 * import { useNuqsAdapter } from '@/lib/store/adapters/nuqs';
 *
 * const adapter = useNuqsAdapter(schema.definition, { id: 'my-table' });
 *
 * // 3. Use in component
 * import { DataTableStoreProvider, useFilterState, useFilterActions } from '@/lib/store';
 *
 * function MyTable() {
 *   return (
 *     <DataTableStoreProvider adapter={adapter}>
 *       <FilterControls />
 *       <DataTable />
 *     </DataTableStoreProvider>
 *   );
 * }
 *
 * function FilterControls() {
 *   const state = useFilterState();
 *   const { setFilter, resetAllFilters } = useFilterActions();
 *   // ...
 * }
 * ```
 */

// Schema
