/**
 * nuqs Server Utilities for BYOS
 *
 * Server-side utilities for creating search params cache and serializers
 * from BYOS schema definitions. Import this from server components or API routes.
 *
 * @example
 * ```typescript
 * // In your schema file (e.g., search-params.ts)
 * import { createNuqsSearchParams } from '@/lib/store/adapters/nuqs/server';
 * import { filterSchema } from './schema';
 *
 * // Create search params utilities from schema
 * export const {
 *   searchParamsParser,
 *   searchParamsCache,
 *   searchParamsSerializer,
 * } = createNuqsSearchParams(filterSchema.definition, {
 *   // Add extra parsers for pagination, etc.
 *   extraParsers: {
 *     size: parseAsInteger.withDefault(40),
 *     cursor: parseAsTimestamp,
 *   },
 * });
 * ```
 */

import {
  createSearchParamsCache,
  createSerializer,
  type ParserBuilder,
} from "nuqs/server";
import type {SchemaDefinition} from "../../schema/schemaTypes";
import {schemaToNuqsParsers,type SchemaToNuqsParsers} from "./parser-bridge";

export type {SchemaToNuqsParsers} from "./parser-bridge";

/**
 * Options for creating nuqs search params utilities
 */
export interface CreateNuqsSearchParamsOptions<
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  TExtra extends Record<string,ParserBuilder<any>>={},
> {
  /**
   * Additional parsers to include (e.g., pagination params)
   */
  extraParsers?: TExtra;
}

/**
 * Result of createNuqsSearchParams
 */
export interface NuqsSearchParamsResult<
  TSchema extends SchemaDefinition,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  TExtra extends Record<string,ParserBuilder<any>>={},
> {
  /**
   * Combined parser object for useQueryStates
   */
  searchParamsParser: SchemaToNuqsParsers<TSchema>&TExtra;

  /**
   * Search params cache for server-side parsing
   */
  searchParamsCache: ReturnType<
    typeof createSearchParamsCache<SchemaToNuqsParsers<TSchema>&TExtra>
  >;

  /**
   * Serializer for converting state to URL string
   */
  searchParamsSerializer: ReturnType<
    typeof createSerializer<SchemaToNuqsParsers<TSchema>&TExtra>
  >;
}

/**
 * Create nuqs search params utilities from a BYOS schema
 *
 * This creates searchParamsParser, searchParamsCache, and searchParamsSerializer
 * from a schema definition, with optional extra parsers for pagination etc.
 *
 * @example
 * ```typescript
 * import { createNuqsSearchParams } from '@/lib/store/adapters/nuqs/server';
 * import { parseAsInteger, parseAsTimestamp } from 'nuqs/server';
 *
 * export const {
 *   searchParamsParser,
 *   searchParamsCache,
 *   searchParamsSerializer,
 * } = createNuqsSearchParams(filterSchema.definition, {
 *   extraParsers: {
 *     size: parseAsInteger.withDefault(40),
 *     start: parseAsInteger.withDefault(0),
 *     cursor: parseAsTimestamp,
 *   },
 * });
 * ```
 */
export function createNuqsSearchParams<
  TSchema extends SchemaDefinition,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  TExtra extends Record<string,ParserBuilder<any>>={},
>(
  schema: TSchema,
  options: CreateNuqsSearchParamsOptions<TExtra>={},
): NuqsSearchParamsResult<TSchema,TExtra> {
  const {extraParsers={} as TExtra}=options;

  // Generate parsers from schema
  const schemaParsers=schemaToNuqsParsers(schema);

  // Combine with extra parsers
  const searchParamsParser={
    ...schemaParsers,
    ...extraParsers,
  } as SchemaToNuqsParsers<TSchema>&TExtra;

  // Create cache and serializer
  const searchParamsCache=createSearchParamsCache(searchParamsParser);
  const searchParamsSerializer=createSerializer(searchParamsParser);

  return {
    searchParamsParser,
    searchParamsCache,
    searchParamsSerializer,
  };
}

// Re-export commonly used nuqs parsers for convenience
export {
  createParser,parseAsArrayOf,
  parseAsBoolean,
  parseAsInteger,
  parseAsString,
  parseAsStringLiteral,
  parseAsTimestamp,type inferParserType,type ParserBuilder
} from "nuqs/server";

// Re-export schema parser utilities
export {createSchemaSerializer,schemaToNuqsParsers} from "./parser-bridge";

/**
 * Parser Bridge - Converts BYOS schema to nuqs parsers
 *
 * This module bridges our schema field definitions to nuqs parser format.
 */

import {SORT_DELIMITER} from "@/lib/delimiters";
import {
  createParser,
  parseAsArrayOf,
  parseAsBoolean,
  parseAsInteger,
  parseAsString,
  parseAsStringLiteral,
  parseAsTimestamp,
  type ParserBuilder,
} from "nuqs/server";
import type {
  FieldBuilder,
  FieldConfig,
  SchemaDefinition,
} from "../../schema/schemaTypes";

/**
 * Type mapping: Schema field type → nuqs ParserBuilder type
 */
export type SchemaToNuqsParsers<T extends SchemaDefinition>={
  [K in keyof T]: T[K] extends FieldBuilder<infer U>
  ? ParserBuilder<U>
  :ParserBuilder<unknown>;
};

/**
 * Convert a single field config to a nuqs parser
 */
function fieldConfigToParser(
  config: FieldConfig<unknown>,
): ParserBuilder<unknown> {
  switch (config.type) {
    case "string":
      return parseAsString as ParserBuilder<unknown>;

    case "number":
      return parseAsInteger as ParserBuilder<unknown>;

    case "boolean":
      return parseAsBoolean as ParserBuilder<unknown>;

    case "timestamp":
      return parseAsTimestamp as ParserBuilder<unknown>;

    case "stringLiteral":
      if (config.literals) {
        return parseAsStringLiteral(
          config.literals as unknown as readonly string[],
        ) as ParserBuilder<unknown>;
      }
      return parseAsString as ParserBuilder<unknown>;

    case "array":
      if (config.itemConfig) {
        const itemParser=fieldConfigToParser(config.itemConfig);
        return parseAsArrayOf(
          itemParser as ParserBuilder<string>,
          config.delimiter,
        ) as ParserBuilder<unknown>;
      }
      return parseAsArrayOf(
        parseAsString,
        config.delimiter,
      ) as ParserBuilder<unknown>;

    case "sort":
      return createParser({
        parse(queryValue: string) {
          const [id,desc]=queryValue.split(SORT_DELIMITER);
          if (!id) return null;
          return {id,desc: desc==="desc"};
        },
        serialize(value: {id: string; desc: boolean}) {
          return `${value.id}${SORT_DELIMITER}${value.desc? "desc":"asc"}`;
        },
      }) as ParserBuilder<unknown>;

    default:
      return parseAsString as ParserBuilder<unknown>;
  }
}

/**
 * Apply default value to a nuqs parser
 */
function applyDefault(
  parser: ParserBuilder<unknown>,
  defaultValue: unknown,
): ParserBuilder<unknown> {
  if (defaultValue!==null&&defaultValue!==undefined) {
    // Arrays default to empty array, not worth adding .withDefault
    if (Array.isArray(defaultValue)&&defaultValue.length===0) {
      return parser;
    }
    // Only apply withDefault for non-null primitive defaults
    if (
      typeof defaultValue==="string"||
      typeof defaultValue==="number"||
      typeof defaultValue==="boolean"||
      defaultValue instanceof Date
    ) {
      return (
        parser as ParserBuilder<unknown>&{
          withDefault: (d: unknown) => ParserBuilder<unknown>;
        }
      ).withDefault(defaultValue);
    }
  }
  return parser;
}

/**
 * Convert a schema definition to nuqs parsers
 *
 * @example
 * ```typescript
 * const schema = createSchema({
 *   level: field.array(field.string()),
 *   latency: field.number(),
 * });
 *
 * // Type is inferred: { level: ParserBuilder<string[]>, latency: ParserBuilder<number> }
 * const parsers = schemaToNuqsParsers(schema.definition);
 * ```
 */
export function schemaToNuqsParsers<T extends SchemaDefinition>(
  schema: T,
): SchemaToNuqsParsers<T> {
  const parsers: Record<string,ParserBuilder<unknown>>={};

  for (const [key,fieldBuilder] of Object.entries(schema)) {
    const config=fieldBuilder._config;
    let parser=fieldConfigToParser(config);
    parser=applyDefault(parser,config.defaultValue);
    parsers[key]=parser;
  }

  return parsers as SchemaToNuqsParsers<T>;
}

/**
 * Create a nuqs cache serializer from schema
 */
export function createSchemaSerializer(schema: SchemaDefinition) {
  const parsers=schemaToNuqsParsers(schema);

  return (state: Record<string,unknown>): string => {
    const params=new URLSearchParams();

    for (const [key,parser] of Object.entries(parsers)) {
      const value=state[key];
      if (value===null||value===undefined) continue;
      if (Array.isArray(value)&&value.length===0) continue;

      try {
        const serialized=(
          parser as {serialize?: (v: unknown) => string}
        ).serialize?.(value);
        if (serialized) {
          params.set(key,serialized);
        }
      } catch {
        // Skip invalid values
      }
    }

    const str=params.toString();
    return str? `?${str}`:"";
  };
}

/**
 * nuqs Adapter for BYOS
 *
 * This adapter uses nuqs for URL-based state management.
 * It supports SSR and URL synchronization.
 */

"use client";

import {useQueryStates,type ParserBuilder} from "nuqs";
import {useEffect,useMemo,useRef} from "react";
import type {InternalStoreAdapter} from "../../adapter/adapterTypes";
import type {SchemaDefinition,StoreSnapshot} from "../../schema/schemaTypes";
import {getSchemaDefaults,validateState} from "../../schema/serialization";
import type {NuqsAdapterOptions} from "./nuqsTypes";
import {schemaToNuqsParsers} from "./parser-bridge";

/**
 * Create a nuqs adapter for URL-based state management
 *
 * @example
 * ```typescript
 * const schema = createSchema({
 *   regions: field.array(field.string()).default([]),
 *   host: field.string(),
 * });
 *
 * function MyComponent() {
 *   const adapter = useNuqsAdapter(schema.definition, { id: 'my-table' });
 *   return (
 *     <DataTableStoreProvider adapter={adapter}>
 *       <DataTable />
 *     </DataTableStoreProvider>
 *   );
 * }
 * ```
 */
export function useNuqsAdapter<T extends Record<string,unknown>>(
  schema: SchemaDefinition,
  options: NuqsAdapterOptions<T>,
): InternalStoreAdapter<T> {
  const {
    id,
    initialState,
    shallow=true,
    history="push",
    scroll=false,
    throttleMs=50,
  }=options;

  const parsers=useMemo(() => schemaToNuqsParsers(schema),[schema]);
  const defaults=useMemo(() => getSchemaDefaults(schema) as T,[schema]);

  // Use nuqs hook
  const [nuqsState,setNuqsState]=useQueryStates(
    parsers as Record<string,ParserBuilder<unknown>>,
    {
      shallow,
      history,
      scroll,
      throttleMs,
    },
  );

  // Store state and version
  const stateRef=useRef<T>(defaults);
  const versionRef=useRef(0);
  const listenersRef=useRef(new Set<() => void>());
  const pausedRef=useRef(false);
  const pendingStateRef=useRef<Partial<T>|null>(null);

  // Cache server snapshot to avoid infinite loop with useSyncExternalStore
  const serverSnapshotRef=useRef<StoreSnapshot<T>>({
    state: {...defaults,...initialState} as T,
    version: 0,
  });

  // Sync nuqs state to our state ref synchronously (needed for first render)
  const validated=validateState(schema,nuqsState) as T;
  const currentState={...defaults,...initialState,...validated};
  if (stateRef.current!==currentState) {
    stateRef.current=currentState;
  }

  // Also update via effect to trigger listeners on subsequent changes
  useEffect(() => {
    const validated=validateState(schema,nuqsState) as T;
    const merged={...defaults,...initialState,...validated};
    stateRef.current=merged;
    versionRef.current++;
    listenersRef.current.forEach((listener) => listener());
  },[nuqsState,schema,defaults,initialState]);

  // Create stable adapter reference
  const adapter=useMemo<InternalStoreAdapter<T>>(() => {
    return {
      subscribe(listener: () => void) {
        listenersRef.current.add(listener);
        return () => {
          listenersRef.current.delete(listener);
        };
      },

      getSnapshot(): StoreSnapshot<T> {
        return {
          state: stateRef.current,
          version: versionRef.current,
        };
      },

      getServerSnapshot(): StoreSnapshot<T> {
        // Return cached snapshot to avoid infinite loop with useSyncExternalStore
        return serverSnapshotRef.current;
      },

      setState(partial: Partial<T>) {
        if (pausedRef.current) {
          pendingStateRef.current={
            ...pendingStateRef.current,
            ...partial,
          };
          return;
        }

        // Convert undefined values to null for nuqs
        const nuqsPartial: Record<string,unknown>={};
        for (const [key,value] of Object.entries(partial)) {
          nuqsPartial[key]=value===undefined? null:value;
        }

        setNuqsState((prev) => ({...prev,...nuqsPartial}));
      },

      setField<K extends keyof T>(key: K,value: T[K]) {
        this.setState({[key]: value} as unknown as Partial<T>);
      },

      reset(fields?: (keyof T)[]) {
        if (fields) {
          const resetPartial: Partial<T>={};
          for (const field of fields) {
            resetPartial[field]=defaults[field];
          }
          this.setState(resetPartial);
        } else {
          this.setState(defaults);
        }
      },

      pause() {
        pausedRef.current=true;
      },

      resume() {
        pausedRef.current=false;
        if (pendingStateRef.current) {
          this.setState(pendingStateRef.current);
          pendingStateRef.current=null;
        }
      },

      isPaused() {
        return pausedRef.current;
      },

      destroy() {
        listenersRef.current.clear();
      },

      getTableId() {
        return id;
      },

      getSchema() {
        return schema;
      },

      getDefaults() {
        return defaults;
      },

      // Internal methods for provider sync
      _syncState(state: T) {
        stateRef.current=state;
        versionRef.current++;
        listenersRef.current.forEach((listener) => listener());
      },
    };
  },[id,schema,defaults,initialState,setNuqsState]);

  return adapter;
}

// Re-export parser bridge utilities for advanced use cases
export {createSchemaSerializer,schemaToNuqsParsers} from "./parser-bridge";

// Re-export nuqs types for components that need them
// This allows components to import from the adapter layer instead of nuqs directly
export type {ParserBuilder} from "nuqs";

/**
 * Text Parser Implementation
 *
 * Standalone module for parsing filter command text input.
 */

import type {
  FieldBuilder,
  InferSchemaType,
  SchemaDefinition,
} from "../schema/schemaTypes";
import type {TextParser,TextParserOptions} from "./types";

/**
 * Create a text parser for filter command input
 *
 * @example
 * ```typescript
 * import { createTextParser } from '@/lib/store/parser';
 *
 * const parser = createTextParser(schema.definition, {
 *   aliases: { l: 'level', r: 'regions' },
 * });
 *
 * // Parse text to state
 * const state = parser.parse('level:error,warn regions:ams');
 *
 * // Serialize state to text
 * const text = parser.serialize({ level: ['error', 'warn'], regions: ['ams'] });
 * ```
 */
export function createTextParser<T extends SchemaDefinition>(
  schema: T,
  options: TextParserOptions={},
): TextParser<T> {
  const {
    aliases={},
    fieldDelimiter=" ",
    keyValueDelimiter=":",
  }=options;

  // Build reverse alias map
  const reverseAliases: Record<string,string>={};
  for (const [alias,field] of Object.entries(aliases)) {
    reverseAliases[field]=alias;
  }

  // Resolve alias to field name
  const resolveAlias=(key: string): string => {
    return aliases[key]||key;
  };

  return {
    parse(input: string): Partial<InferSchemaType<T>> {
      const result: Record<string,unknown>={};

      if (!input.trim()) {
        return result as Partial<InferSchemaType<T>>;
      }

      // Split by field delimiter, but handle quoted values
      const parts=input
        .trim()
        .split(new RegExp(`\\s*${escapeRegex(fieldDelimiter)}\\s*`));

      for (const part of parts) {
        if (!part) continue;

        const colonIndex=part.indexOf(keyValueDelimiter);
        if (colonIndex===-1) continue;

        const rawKey=part.slice(0,colonIndex).trim();
        const rawValue=part.slice(colonIndex+1).trim();

        if (!rawKey||!rawValue) continue;

        const fieldKey=resolveAlias(rawKey);
        const fieldBuilder=schema[fieldKey] as
          |FieldBuilder<unknown>
          |undefined;

        if (!fieldBuilder) continue;

        try {
          const parsed=fieldBuilder._config.parse(rawValue);
          if (parsed!==null) {
            result[fieldKey]=parsed;
          }
        } catch {
          // Skip invalid values
        }
      }

      return result as Partial<InferSchemaType<T>>;
    },

    serialize(state: Partial<InferSchemaType<T>>): string {
      const parts: string[]=[];

      for (const [key,value] of Object.entries(state)) {
        if (value===null||value===undefined) continue;
        if (Array.isArray(value)&&value.length===0) continue;

        const fieldBuilder=schema[key] as FieldBuilder<unknown>|undefined;
        if (!fieldBuilder) continue;

        try {
          const serialized=fieldBuilder._config.serialize(value);
          if (serialized) {
            parts.push(`${key}${keyValueDelimiter}${serialized}`);
          }
        } catch {
          // Skip invalid values
        }
      }

      return parts.join(fieldDelimiter);
    },

    getWordAtCaret(input: string,caretPosition: number) {
      // Find word boundaries
      let start=caretPosition;
      let end=caretPosition;

      // Move start backwards to find word start
      while (start>0&&input[start-1]!==fieldDelimiter) {
        start--;
      }

      // Move end forwards to find word end
      while (end<input.length&&input[end]!==fieldDelimiter) {
        end++;
      }

      const word=input.slice(start,end);
      const colonIndex=word.indexOf(keyValueDelimiter);

      let field: string|null=null;
      let value: string|null=null;

      if (colonIndex!==-1) {
        field=resolveAlias(word.slice(0,colonIndex));
        value=word.slice(colonIndex+1);
      } else {
        // Could be a partial field name
        field=null;
        value=null;
      }

      return {word,start,end,field,value};
    },

    replaceWordAtCaret(
      input: string,
      caretPosition: number,
      replacement: string,
    ) {
      const {start,end}=this.getWordAtCaret(input,caretPosition);

      const before=input.slice(0,start);
      const after=input.slice(end);

      const newInput=before+replacement+after;
      const newCaretPosition=start+replacement.length;

      return {newInput,newCaretPosition};
    },

    getSuggestions(
      input: string,
      caretPosition: number,
      fieldOptions: Record<string,string[]>,
    ) {
      const {word,field,value}=this.getWordAtCaret(input,caretPosition);

      // If we have a field and are typing a value
      if (field&&value!==null) {
        const options=fieldOptions[field]||[];
        const filtered=options.filter((opt) =>
          opt.toLowerCase().includes(value.toLowerCase()),
        );

        return {
          type: "value" as const,
          field,
          suggestions: filtered,
        };
      }

      // Otherwise, suggest field names
      const schemaKeys=Object.keys(schema);
      const aliasKeys=Object.keys(aliases);
      const allFields=[...schemaKeys,...aliasKeys];

      const filtered=word
        ? allFields.filter((f) =>
          f.toLowerCase().startsWith(word.toLowerCase()),
        )
        :allFields;

      return {
        type: "field" as const,
        suggestions: filtered,
      };
    },
  };
}

/**
 * Escape special regex characters
 */
function escapeRegex(str: string): string {
  return str.replace(/[.*+?^${}()|[\]\\]/g,"\\$&");
}

/**
 * Text Parser Types
 */

import type {InferSchemaType,SchemaDefinition} from "../schema/schemaTypes";

/**
 * Options for creating a text parser
 */
export interface TextParserOptions {
  /**
   * Field aliases for shorthand (e.g., { l: 'level', r: 'regions' })
   */
  aliases?: Record<string,string>;

  /**
   * Delimiter between field:value pairs (default: ' ')
   */
  fieldDelimiter?: string;

  /**
   * Delimiter between field and value (default: ':')
   */
  keyValueDelimiter?: string;
}

/**
 * Text parser interface
 */
export interface TextParser<T extends SchemaDefinition> {
  /**
   * Parse a text input string into filter state
   *
   * @example
   * ```typescript
   * parser.parse('regions:ams,gru latency:0-1000');
   * // => { regions: ['ams', 'gru'], latency: [0, 1000] }
   * ```
   */
  parse(input: string): Partial<InferSchemaType<T>>;

  /**
   * Serialize filter state to text format
   *
   * @example
   * ```typescript
   * parser.serialize({ regions: ['ams', 'gru'], latency: [0, 1000] });
   * // => 'regions:ams,gru latency:0-1000'
   * ```
   */
  serialize(state: Partial<InferSchemaType<T>>): string;

  /**
   * Get the current word at caret position
   */
  getWordAtCaret(
    input: string,
    caretPosition: number,
  ): {
    word: string;
    start: number;
    end: number;
    field: string|null;
    value: string|null;
  };

  /**
   * Replace the current word at caret position
   */
  replaceWordAtCaret(
    input: string,
    caretPosition: number,
    replacement: string,
  ): {
    newInput: string;
    newCaretPosition: number;
  };

  /**
   * Get suggestions for autocomplete
   */
  getSuggestions(
    input: string,
    caretPosition: number,
    fieldOptions: Record<string,string[]>,
  ): {
    type: "field"|"value";
    field?: string;
    suggestions: string[];
  };
}

/**
 * DataTableStoreProvider - Main provider for BYOS
 *
 * Wraps components with store adapter context.
 */

"use client";

import React,{useEffect,useMemo} from "react";
import type {StoreAdapter} from "../adapter/adapterTypes";
import {StoreContext,type StoreContextValue} from "../context";

export interface DataTableStoreProviderProps<
  T extends Record<string,unknown>,
> {
  /**
   * The store adapter to use
   */
  adapter: StoreAdapter<T>;

  /**
   * Child components
   */
  children: React.ReactNode;
}

/**
 * Provider component for data table store
 *
 * @example
 * ```typescript
 * const adapter = useNuqsAdapter(schema.definition, { id: 'my-table' });
 *
 * return (
 *   <DataTableStoreProvider adapter={adapter}>
 *     <DataTable />
 *   </DataTableStoreProvider>
 * );
 * ```
 */
export function DataTableStoreProvider<T extends Record<string,unknown>>({
  adapter,
  children,
}: DataTableStoreProviderProps<T>) {
  const value=useMemo<StoreContextValue<T>>(
    () => ({
      adapter,
      schema: adapter.getSchema(),
      tableId: adapter.getTableId(),
    }),
    [adapter],
  );

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      adapter.destroy();
    };
  },[adapter]);

  return (
    <StoreContext.Provider
      value={value as StoreContextValue<Record<string,unknown>>}
    >
      {children}
    </StoreContext.Provider>
  );
}

/**
 * useFilterState Hook
 *
 * Read filter state from the store adapter.
 */

"use client";

import { useCallback, useSyncExternalStore } from "react";
import { useStoreContext } from "../context";

/**
 * Hook to read filter state from the adapter
 *
 * @example
 * ```typescript
 * // Read entire state
 * const state = useFilterState();
 *
 * // Read with selector (for performance)
 * const regions = useFilterState(s => s.regions);
 * ```
 */
export function useFilterState<T extends Record<string, unknown>, R = T>(
  selector?: (state: T) => R,
): R {
  const context = useStoreContext();

  if (!context) {
    throw new Error(
      "useFilterState must be used within a DataTableStoreProvider",
    );
  }

  const { adapter } = context;

  const subscribe = useCallback(
    (onStoreChange: () => void) => adapter.subscribe(onStoreChange),
    [adapter],
  );

  const getSnapshot = useCallback(() => {
    const snapshot = adapter.getSnapshot();
    const state = snapshot.state as T;
    return selector ? selector(state) : (state as unknown as R);
  }, [adapter, selector]);

  const getServerSnapshot = useCallback(() => {
    const snapshot = adapter.getServerSnapshot?.() ?? adapter.getSnapshot();
    const state = snapshot.state as T;
    return selector ? selector(state) : (state as unknown as R);
  }, [adapter, selector]);

  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

/**
 * useFilterActions Hook
 *
 * Get actions to modify filter state.
 */

"use client";

import {useStoreContext} from "@/lib/store/context";
import {useCallback,useMemo} from "react";

/**
 * Actions returned by useFilterActions
 */
export interface FilterActions<T extends Record<string,unknown>> {
  /**
   * Set a single filter field value
   */
  setFilter: <K extends keyof T>(key: K,value: T[K]) => void;

  /**
   * Set multiple filter fields at once
   */
  setFilters: (partial: Partial<T>) => void;

  /**
   * Reset a single filter field to its default value
   */
  resetFilter: (key: keyof T) => void;

  /**
   * Reset all filters to default values
   */
  resetAllFilters: () => void;

  /**
   * Pause state updates (for live mode)
   */
  pause: () => void;

  /**
   * Resume state updates
   */
  resume: () => void;

  /**
   * Check if updates are paused
   */
  isPaused: () => boolean;
}

/**
 * Hook to get filter actions
 *
 * @example
 * ```typescript
 * const { setFilter, setFilters, resetAllFilters, pause, resume } = useFilterActions();
 *
 * // Set single field
 * setFilter('regions', ['ams', 'gru']);
 *
 * // Set multiple fields
 * setFilters({ regions: ['ams'], host: 'api.example.com' });
 *
 * // Reset all
 * resetAllFilters();
 *
 * // Pause/resume for live mode
 * pause();
 * resume();
 * ```
 */
export function useFilterActions<T extends Record<string,unknown>>(): FilterActions<T> {
  const context=useStoreContext();

  if (!context) {
    throw new Error(
      "useFilterActions must be used within a DataTableStoreProvider",
    );
  }

  const {adapter}=context;

  const setFilter=useCallback(
    <K extends keyof T>(key: K,value: T[K]) => {
      adapter.setField(key as string,value);
    },
    [adapter],
  );

  const setFilters=useCallback(
    (partial: Partial<T>) => {
      adapter.setState(partial as Partial<Record<string,unknown>>);
    },
    [adapter],
  );

  const resetFilter=useCallback(
    (key: keyof T) => {
      adapter.reset([key as string]);
    },
    [adapter],
  );

  const resetAllFilters=useCallback(() => {
    adapter.reset();
  },[adapter]);

  const pause=useCallback(() => {
    adapter.pause();
  },[adapter]);

  const resume=useCallback(() => {
    adapter.resume();
  },[adapter]);

  const isPaused=useCallback(() => {
    return adapter.isPaused();
  },[adapter]);

  return useMemo(
    () => ({
      setFilter,
      setFilters,
      resetFilter,
      resetAllFilters,
      pause,
      resume,
      isPaused,
    }),
    [
      setFilter,
      setFilters,
      resetFilter,
      resetAllFilters,
      pause,
      resume,
      isPaused,
    ],
  );
}

/**
 * useFilterField Hook
 *
 * Hook for working with a single filter field.
 */

"use client";

import { useCallback, useMemo, useSyncExternalStore } from "react";
import { useStoreContext } from "../context";

/**
 * Return type for useFilterField
 */
export interface FilterFieldResult<T> {
  /**
   * Current value of the field
   */
  value: T;

  /**
   * Set the field value
   */
  setValue: (value: T) => void;

  /**
   * Reset the field to its default value
   */
  reset: () => void;
}

/**
 * Hook to work with a single filter field
 *
 * @example
 * ```typescript
 * const { value, setValue, reset } = useFilterField<FilterState, 'regions'>('regions');
 *
 * // Read value
 * console.log(value); // ['ams', 'gru']
 *
 * // Update value
 * setValue(['ams', 'gru', 'fra']);
 *
 * // Reset to default
 * reset();
 * ```
 */
export function useFilterField<
  T extends Record<string, unknown>,
  K extends keyof T,
>(key: K): FilterFieldResult<T[K]> {
  const context = useStoreContext();

  if (!context) {
    throw new Error(
      "useFilterField must be used within a DataTableStoreProvider",
    );
  }

  const { adapter } = context;

  const subscribe = useCallback(
    (onStoreChange: () => void) => adapter.subscribe(onStoreChange),
    [adapter],
  );

  const getSnapshot = useCallback(() => {
    const snapshot = adapter.getSnapshot();
    return (snapshot.state as T)[key];
  }, [adapter, key]);

  const getServerSnapshot = useCallback(() => {
    const snapshot = adapter.getServerSnapshot?.() ?? adapter.getSnapshot();
    return (snapshot.state as T)[key];
  }, [adapter, key]);

  const value = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);

  const setValue = useCallback(
    (newValue: T[K]) => {
      adapter.setField(key as string, newValue);
    },
    [adapter, key],
  );

  const reset = useCallback(() => {
    adapter.reset([key as string]);
  }, [adapter, key]);

  return useMemo(() => ({ value, setValue, reset }), [value, setValue, reset]);
}

/**
 * useReactTableSync Hook
 *
 * Syncs BYOS filter state with React Table's columnFilters.
 * This hook provides bidirectional synchronization between the adapter state
 * and React Table's internal state.
 */

"use client";

import type { DataTableFilterField } from "@/components/data-table/types";
import type { ColumnFiltersState, Table } from "@tanstack/react-table";
import { useCallback, useEffect, useRef } from "react";
import { useFilterActions } from "./useFilterActions";
import { useFilterState } from "./useFilterState";

interface UseReactTableSyncOptions<TData> {
  /**
   * React Table instance
   */
  table: Table<TData>;

  /**
   * Filter field definitions (to know which fields to sync)
   */
  filterFields: DataTableFilterField<TData>[];

  /**
   * Callback when column filters change (from table)
   */
  onColumnFiltersChange?: (filters: ColumnFiltersState) => void;
}

/**
 * Hook to synchronize BYOS adapter state with React Table
 *
 * @example
 * ```typescript
 * const table = useReactTable({ ... });
 *
 * useReactTableSync({
 *   table,
 *   filterFields,
 * });
 * ```
 */
export function useReactTableSync<TData>({
  table,
  filterFields,
  onColumnFiltersChange,
}: UseReactTableSyncOptions<TData>) {
  const filterState = useFilterState<Record<string, unknown>>();
  const { setFilters } = useFilterActions<Record<string, unknown>>();

  // Track if we're currently syncing to avoid loops
  const isSyncingRef = useRef(false);

  // Sync BYOS state → React Table
  useEffect(() => {
    if (isSyncingRef.current) return;

    isSyncingRef.current = true;

    // Convert filter state to column filters format
    for (const field of filterFields) {
      const fieldKey = field.value as string;
      const value = filterState[fieldKey];
      const column = table.getColumn(fieldKey);

      if (column) {
        // Only update if value is different
        const currentValue = column.getFilterValue();
        if (!isEqual(currentValue, value)) {
          column.setFilterValue(value ?? undefined);
        }
      }
    }

    isSyncingRef.current = false;
  }, [filterState, filterFields, table]);

  // Sync React Table → BYOS state (via callback)
  const syncFromTable = useCallback(() => {
    if (isSyncingRef.current) return;

    isSyncingRef.current = true;

    const columnFilters = table.getState().columnFilters;
    const updates: Record<string, unknown> = {};

    for (const field of filterFields) {
      const fieldKey = field.value as string;
      const filter = columnFilters.find((f) => f.id === fieldKey);
      updates[fieldKey] = filter?.value ?? null;
    }

    setFilters(updates);
    onColumnFiltersChange?.(columnFilters);

    isSyncingRef.current = false;
  }, [table, filterFields, setFilters, onColumnFiltersChange]);

  return {
    syncFromTable,
  };
}

/**
 * Simple equality check for filter values
 */
function isEqual(a: unknown, b: unknown): boolean {
  if (a === b) return true;
  if (a === null || b === null) return a === b;
  if (a === undefined || b === undefined) return a === b;

  if (Array.isArray(a) && Array.isArray(b)) {
    if (a.length !== b.length) return false;
    return a.every((val, i) => isEqual(val, b[i]));
  }

  if (a instanceof Date && b instanceof Date) {
    return a.getTime() === b.getTime();
  }

  if (typeof a === "object" && typeof b === "object") {
    const keysA = Object.keys(a as object);
    const keysB = Object.keys(b as object);
    if (keysA.length !== keysB.length) return false;
    return keysA.every((key) =>
      isEqual(
        (a as Record<string, unknown>)[key],
        (b as Record<string, unknown>)[key],
      ),
    );
  }

  return false;
}

